  "code": "if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or missing entity.';
}
const startPos = bot.entity.position.clone();
const angle = Math.random() * Math.PI * 2;
const targetX = startPos.x + Math.cos(angle) * args.maxDistanceBlocks;
const targetZ = startPos.z + Math.sin(angle) * args.maxDistanceBlocks;
const targetPos = new Vec3(targetX, startPos.y, targetZ);

startBackgroundSkill(bot, 'move_scout_area', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  movements.allowSprinting = true;
  bot.pathfinder.setMovements(movements);
  const goal = new goals.GoalNear(targetPos.x, targetPos.y, targetPos.z, 2);

  let activeElapsedMs = 0;
  const pollMs = 200;
  const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'baby_zombie', 'enderman', 'witch', 'phantom']);

  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) return;
    bot.pathfinder.setGoal(goal);

    while (canContinueBotAction(bot, token)) {
      if (activeElapsedMs >= args.maxDurationMs) break;
      if (bot.pathfinder.isGoalSatisfied(goal)) break;

      const currentPos = bot.entity.position;

      if (args.scanForHostiles) {
        const threat = Object.values(bot.entities).find(function (e) {
          if (!e || !e.isValid || e.id === bot.entity.id) return false;
          const dist = e.position.distanceTo(currentPos);
          if (dist > args.detectionRadiusBlocks) return false;
          return (e.kind === 'Hostile mobs' || e.type === 'hostile' || hostileNames.has(e.name || ''));
        });
        if (threat) break;
      }

      if (args.scanForItems) {
        const item = Object.values(bot.entities).find(function (e) {
          if (!e || !e.isValid || e.name !== 'item') return false;
          return e.position.distanceTo(currentPos) < Math.min(args.detectionRadiusBlocks, 10);
        });
        if (item) break;
      }

      if (!await waitForActiveMs(bot, token, pollMs)) break;
      activeElapsedMs += pollMs;
    }
  } finally {
    bot.pathfinder.stop();
    bot.pathfinder.setGoal(null);
  }
});

return '<STARTED>: Scouting toward ' + targetPos.x.toFixed(1) + ', ' + targetZ.toFixed(1) + ' with scanning enabled.';"
}

