  "code": "const pollMs = 100;
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}
const teammate = bot.players[args.teammateName]?.entity || Object.values(bot.entities).find(function(e) { return e.type === 'player' && e.username === args.teammateName; });
if (!teammate) {
  return '<NO TARGET>: Could not find teammate ' + args.teammateName + ' to regroup with.';
}
const angle = Math.random() * Math.PI * 2;
const scoutTarget = bot.entity.position.offset(Math.cos(angle) * args.maxDistanceBlocks, 0, Math.sin(angle) * args.maxDistanceBlocks);
startBackgroundSkill(bot, 'scout_random_direction', async function (token) {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) return;
    bot.pathfinder.setGoal(new goals.GoalNear(scoutTarget.x, scoutTarget.y, scoutTarget.z, 1));
    let elapsed = 0;
    while (elapsed < args.maxScoutDurationMs && canContinueBotAction(bot, token)) {
      const isNearScout = bot.entity.position.distanceTo(scoutTarget) < 2;
      if (isNearScout) break;
      if (args.stopOnDiscovery) {
        const nearbyHostiles = Object.values(bot.entities).some(function(e) {
          const isHostile = (e.kind === 'Hostile mobs' || e.type === 'hostile' || ['zombie', 'skeleton', 'creeper', 'spider', 'husk'].includes(e.name));
          return isHostile && e.position.distanceTo(bot.entity.position) < 15 && e.isValid;
        });
        const nearbyItems = Object.values(bot.entities).some(function(e) {
          return e.name === 'item' && e.position.distanceTo(bot.entity.position) < 10 && e.isValid;
        });
        if (nearbyHostiles || nearbyItems) break;
      }
      if (!await waitForActiveMs(bot, token, pollMs, pollMs)) return;
      elapsed += pollMs;
    }
    bot.pathfinder.stop();
    if (!canContinueBotAction(bot, token)) return;
    const regroupMovements = new Movements(bot);
    regroupMovements.canDig = false;
    bot.pathfinder.setMovements(regroupMovements);
    while (canContinueBotAction(bot, token)) {
      const currentTeammate = bot.players[args.teammateName]?.entity || Object.values(bot.entities).find(function(e) { return e.type === 'player' && e.username === args.teammateName; });
      if (!currentTeammate) break;
      const dist = bot.entity.position.distanceTo(currentTeammate.position);
      if (dist < 3) break;
      if (!bot.pathfinder.goal || bot.pathfinder.goal.x !== currentTeammate.position.x) {
        bot.pathfinder.setGoal(new goals.GoalFollow(currentTeammate, 2), true);
      }
      if (!await waitForActiveMs(bot, token, 500, pollMs)) return;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.pathfinder.stop();
    bot.clearControlStates();
  }
});
return '<STARTED>: Scouting in random direction for ' + args.maxDistanceBlocks + ' blocks, then regrouping with ' + args.teammateName + '.';"
}
